#include<cstring>
#include<iostream>
#include<algorithm>
#include<cmath>
#define int long long
using namespace std;

int fa[1005];
int x[1005]; int y[1005];int z[1005];

int find(int x)
{
	return fa[x] == x ? x : fa[x] = find(fa[x]);
}

void merge(int x, int y)
{
	fa[find(x)] = find(y);
}

int dist(int i, int j)
{
	return (x[i] - x[j]) * (x[i] - x[j]) + (y[i] - y[j]) * (y[i] - y[j]) + (z[i] - z[j]) * (z[i] - z[j]);
}

signed main(){
	int t;
	cin >> t;
	while(t--)
	{
		int n, h, r;
		cin >> n >> h >> r;
		for(int i = 1; i <= n; i++)
			cin >> x[i] >> y[i] >> z[i];
		for(int i = 0; i <= n + 1; i++)
			fa[i] = i;
		for(int i = 1; i <= n; i++)
		{
			if(z[i] <= r) merge(i, 0);
			if(z[i] >= h - r) merge(i, n + 1);
			for(int j = 1; j <= n; j++)
			{
				if(dist(i, j) > 4 * r * r) continue;
				if(find(i) != find(j)) merge(i, j);
			}
		}
		if(find(0) == find(n + 1)) cout << "Yes\n";
		else cout << "No\n";
	}
	return 0;
}
